import React from 'react'

export default function Calculator(props) {
    document.title = 'Calculator';
  return (
        
      <div className='container my-5 mx-5'>
      <textarea className='form-control' name="textInput" id="inputWindow" value={props.exp} readOnly style={{fontSize:20}}></textarea>
      <table className="table table-primary table-bordered my-2" >
        <thead>
            <tr>
            <th  scope="col"><button className='btn btn-secondary px-5' onClick={props.inputExpression}>AC</button></th>
            <th  scope="col"><button className='btn btn-secondary px-5' id = 'Backspace' onClick={props.inputExpression}><img src= "/backspace.png" alt="backspace" id = 'Backspace' height="20"/></button></th>
            <th  scope="col"><button className='btn btn-secondary px-5' onClick={props.inputExpression}>%</button></th>
            <th  scope="col"><button className="btn btn-secondary px-5" id = 'Division' onClick={props.inputExpression}><img src="/division" id = 'Division' alt="division" height="20" /></button></th>
            </tr>
        </thead>
        <tbody>
            <tr>
            <th scope="row"><button className='btn btn-secondary px-5' onClick={props.inputExpression}>7</button></th>
            <td><button className='btn btn-secondary px-5' onClick={props.inputExpression}>8</button></td>
            <td><button className='btn btn-secondary px-5' onClick={props.inputExpression}>9</button></td>
            <td><button className='btn btn-secondary px-5' onClick={props.inputExpression}>*</button></td>
            </tr>
            <tr>
            <th scope="row"><button className='btn btn-secondary px-5' onClick={props.inputExpression}>4</button></th>
            <td><button className='btn btn-secondary px-5' onClick={props.inputExpression}>5</button></td>
            <td><button className='btn btn-secondary px-5' onClick={props.inputExpression}>6</button></td>
            <td><button className='btn btn-secondary px-5' onClick={props.inputExpression}>-</button></td>
            </tr>
            <tr>
            <th scope="row"><button className='btn btn-secondary px-5' onClick={props.inputExpression}>1</button></th>
            <td><button className='btn btn-secondary px-5' onClick={props.inputExpression}>2</button></td>
            <td><button className='btn btn-secondary px-5' onClick={props.inputExpression}>3</button></td>
            <td><button className='btn btn-secondary px-5' onClick={props.inputExpression}>+</button></td>
            </tr>
            <tr>
            <th scope="row"><button className='btn btn-secondary px-5' id = 'squareRoot' onClick={props.inputExpression}><img src= "/squareRoot.png" id = 'squareRoot' alt="backspace" height="20"/></button></th>
            <td><button className='btn btn-secondary px-5' onClick={props.inputExpression}>0</button></td>
            <td><button className='btn btn-secondary px-5' onClick={props.inputExpression}>.</button></td>
            <td><button className='btn btn-secondary px-5' onClick={props.Compute}>=</button></td>
            </tr>
        </tbody>
        </table>
    </div>
  )
}
