import './App.css';
import React from 'react';
import Navbar from './Components/Navbar';
import TextForm from './Components/TextForm';
import Alert from './Components/Alert';
import Calculator from './Components/Calculator';
import $ from 'jquery'
import { useState } from 'react';
import {
  BrowserRouter as Router,
  Routes,
  Route
} from "react-router-dom";

function App() {

  const [mode,setMode] = useState('light');
  const [alert,setAlert] = useState(null)

  const switchToggle = (event)=>{
    var eventSource = event.target.id;
    if(eventSource === 'blueMode'){
      setMode('dark');
      $('textArea').css({color:'Blue'})
      $('.btn').css({backgroundColor:'#012d95'})
      document.body.style.backgroundColor = '#0a0a31'
      showAlert('Blue mode has been enabled.','success')
    }
    else if(eventSource === 'lightMode'){
      setMode('light');
      $('textArea').css({backgroundColor : 'White',color:'Black'})
      $('.btn').css({backgroundColor:'#0a58ca'})
      document.body.style.backgroundColor = 'White'
      showAlert('Light mode has been enabled.','success')
    }
    else if(eventSource === 'GreenMode'){
      setMode('success');
      document.body.style.backgroundColor = '#0e380e'

      $('textArea').css({color:'Green'})
      $('.btn').css({backgroundColor:'Green'})
      showAlert('Green mode has been enabled.','success')
    }
    else if(eventSource === 'RedMode'){
      setMode('dark');
      $('textArea').css({backgroundColor : 'lightGray' ,color:'#360202'})
      $('.btn').css({backgroundColor:'#360202'})
      document.body.style.backgroundColor = '#360202'
      showAlert('Red mode has been enabled.','success')
    }
  }

  function showAlert(msg,type){
    setAlert({
      message : msg,
      type : type
    })

    setTimeout(()=>{setAlert(null)},1500)
  }

  const [expression,setExpression] = useState('0')
  
  function isTextAreaEmpty(){
    if(expression.length === 1 && ( expression === '' || expression === '0'))
      return true;
    return false;
  }

  function inputExpression(event){
    
    var value = event.target.innerText.length === 0 ?event.target.id:event.target.innerText;
    
    switch(value){

      case 'AC':{
        setExpression('0');
        break;
      }
      
      case 'Backspace':{
        var tmp = expression.slice(0,expression.length-1)
        setExpression(tmp);
        break;
      }

      default : {
        
        if(value === 'Division'){
          value = ' / '
        }
        else if(value === 'squareRoot'){
          value = 'Math.sqrt('
        }
        else if(value === '%'){
          value = '/100'
        }
        else if(value === '+' || value === '-'  || value === '*' ){
          value = ' ' + value + ' '
        }

        if(isTextAreaEmpty()){
          setExpression(value);
        }
        else{
          setExpression(expression + value);
        }

        break;
      }
    }
  }

  function Compute(){

    let exp = expression;
    
    if(expression.includes('sqrt(')){
      exp = exp + ")"
      setExpression(exp)
    }
    setExpression(exp + ' = '+ eval(exp))
  }

  return (
    <Router>
      <Navbar title = "Text Editor" mode = {mode} toggleMode = {switchToggle}/>
      <Alert alert = {alert} />
      <Routes>
          <Route path="/" element= {<TextForm heading = "Enter the text below : " mode = {mode} showAlert = {showAlert}/>}></Route>
          <Route path="/Calculator" element = {<Calculator exp = {expression} inputExpression = {inputExpression} Compute = {Compute}/>}></Route>
      </Routes>
    </Router>
  );
}

export default App;