import React from 'react';
import { Link } from 'react-router-dom';

export default function Navbar(props) {
  
  return (
    <nav className={`navbar navbar-expand-lg navbar-${props.mode} bg-${props.mode} py-0`} >
        <div className="container-fluid mx-0"  >
            <img src="favicon.ico" alt="logo" width="20" height="20"/>
            <Link className="navbar-brand mx-2 my-3" style = {{fontSize : 25,fontFamily :'Cambria' }} to='/'>{props.title}</Link>

            <div className="collapse navbar-collapse" id="navbarSupportedContent">
            <ul className="navbar-nav mr-auto">
              <li className="nav-item active">
                <Link className="nav-link" to="/">Home</Link>
              </li>
              <li className="nav-item">
                <Link className="nav-link" to="/Calculator">Calculator</Link>
              </li>
            </ul>
            </div>
            
            <div className="dropdown mx-5 my-3">
              <a className="btn btn-secondary dropdown-toggle" href="/" role="button" data-bs-toggle="dropdown" aria-expanded="false">
                Themes
              </a>
              <ul className="dropdown-menu mx-20" style = {{backgroundColor : props.mode === 'dark'?'Gray':'White'}} >
              <li onClick = {props.toggleMode}>
                <div className="form-check">
                <input className="form-check-input" defaultChecked type="radio" name="exampleRadios" id="lightMode" value="option1"/>
                  <label className="form-check-label" htmlFor="exampleRadios1">
                    Light
                  </label>
                </div>
                <div className="form-check">
                <input className="form-check-input" type="radio" name="exampleRadios" id="blueMode" value="option2" />
                  <label className="form-check-label" htmlFor="blueSwitch">
                    Blue
                  </label>
                </div>
                <div className="form-check">
                  <input className="form-check-input" type="radio" name="exampleRadios" id="GreenMode" value="option3"/>
                  <label className="form-check-label" htmlFor="exampleRadios1">
                    Green
                  </label>
                </div>
                <div className="form-check">
                  <input className="form-check-input" type="radio" name="exampleRadios" id="RedMode" value="option3"/>
                  <label className="form-check-label" htmlFor="exampleRadios1">
                    Red
                  </label>
                </div>
              </li>
              </ul>
        </div>  
      </div>  
    </nav>
  );
}

Navbar.defaultProps = {
    title : "Write title here",
    subTitle1 : "Link1",
    subTitle2 : "Link2",
    dropdown : "DropDown Title",
    dropdown1 : "Link 1",
    dropdown2 : "Link 2",
    dropdown3 : "Link 3",
    disabled : "Disabled Link"
};